// KST 기준 오늘/내일 날짜 범위 계산
const now = new Date();
// UTC+9 오프셋 적용
const kstOffset = 9 * 60 * 60 * 1000;
const kstNow = new Date(now.getTime() + kstOffset);

// KST 기준 오늘 자정 (00:00:00)
const todayStart = new Date(Date.UTC(
  kstNow.getUTCFullYear(),
  kstNow.getUTCMonth(),
  kstNow.getUTCDate()
) - kstOffset);

// KST 기준 내일 자정 (00:00:00)
const tomorrowStart = new Date(todayStart.getTime() + 24 * 60 * 60 * 1000);

// KST 기준 모레 자정 (경계값 — 내일 하루 전체 포함)
const dayAfterTomorrowStart = new Date(tomorrowStart.getTime() + 24 * 60 * 60 * 1000);

// 응답에서 items 추출
const responseData = $input.first().json;
const items = (responseData.explorer && Array.isArray(responseData.explorer.items))
  ? responseData.explorer.items
  : [];

// dueAt이 오늘 또는 내일인 태스크 필터링
const filtered = items.filter(task => {
  if (!task.dueAt) return false;
  const due = new Date(task.dueAt);
  return due >= todayStart && due < dayAfterTomorrowStart;
});

// 태스크별 D-day 라벨 결정 및 메시지 라인 생성
const lines = filtered.map(task => {
  const due = new Date(task.dueAt);
  const label = due >= tomorrowStart ? 'D-1' : 'D-day';
  const assignee = task.assignee || '미지정';
  return `• [${label}] ${task.title} (담당: ${assignee})`;
});

const count = filtered.length;
const shouldSend = count > 0;

let text = '';
if (shouldSend) {
  text = `⏰ 마감 알림\n\n${lines.join('\n')}\n\n총 ${count}건`;
}

return [{ json: { shouldSend, count, text, filtered } }];
